mapper.select:
SELECT STORE_INVENTORY_ID AS inventoryId , CURRENT_QUANTITY , SHORTAGE_QUANTITY , SAFETY_QUANTITY , STORE_NAME , MATERIAL_CODE , MATERIAL_NAME , MATERIAL_TYPE FROM ( SELECT * FROM ( SELECT ROWNUM AS rn, temp.* FROM ( SELECT STORE_INVENTORY_ID , I.CURRENT_QUANTITY , CASE WHEN I.CURRENT_QUANTITY < I.SAFETY_QUANTITY THEN I.CURRENT_QUANTITY - I.SAFETY_QUANTITY ELSE 0 END AS SHORTAGE_QUANTITY , I.SAFETY_QUANTITY , S.STORE_NAME , M.MATERIAL_TYPE || EXTRACT(YEAR FROM M.CREATED_AT) || LPAD(MATERIAL_ID, 4, '0') AS MATERIAL_CODE , M.MATERIAL_NAME , M.MATERIAL_TYPE , STORE_ID , MATERIAL_ID FROM STORE_INVENTORIES I JOIN MATERIALS M USING (MATERIAL_ID) JOIN STORES S USING (STORE_ID)
STORE_ID = #{condition.storeId}
AND MATERIAL_ID = #{condition.materialId}
AND M.MATERIAL_NAME LIKE '%' || #{condition.materialName} || '%'
AND M.MATERIAL_TYPE = #{condition.materialType}
AND I.CURRENT_QUANTITY < I.SAFETY_QUANTITY
ORDER BY I.CREATED_AT DESC, I.STORE_INVENTORY_ID ) temp WHERE ROWNUM <= #{paging.endRow} ) WHERE rn >= #{paging.startRow} )

SELECT COUNT(*) FROM STORE_INVENTORIES I JOIN MATERIALS M USING (MATERIAL_ID) JOIN STORES S USING (STORE_ID)
STORE_ID = #{condition.storeId}
AND MATERIAL_ID = #{condition.materialId}
AND M.MATERIAL_NAME LIKE '%' || #{condition.materialName} || '%'
AND M.MATERIAL_TYPE = #{condition.materialType}
AND I.CURRENT_QUANTITY < I.SAFETY_QUANTITY

mapper.update:
UPDATE STORE_INVENTORIES
   SET CURRENT_QUANTITY = #{inventory.currentQuantity}
     , SAFETY_QUANTITY = #{inventory.safetyQuantity}
     , UPDATED_AT = SYSDATE
 WHERE STORE_INVENTORY_ID = #{inventory.storeInventoryId}

   AND UPDATED_AT = #{inventory.updatedAt}
